namespace sv_76f92376efb64d11ae425cc7df8cad4d.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "New York, NY",
                    Timestamp = new DateTimeOffset(2026, 5, 25, 9, 30, 0, TimeSpan.FromHours(-4))
                },
                new StatusUpdate
                {
                    Description = "Departed sorting facility",
                    Location = "Newark, NJ",
                    Timestamp = new DateTimeOffset(2026, 5, 26, 2, 15, 0, TimeSpan.FromHours(-4))
                },
                new StatusUpdate
                {
                    Description = "Arrived at regional hub",
                    Location = "Chicago, IL",
                    Timestamp = new DateTimeOffset(2026, 5, 27, 14, 45, 0, TimeSpan.FromHours(-5))
                }
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 27, 12, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "Seattle, WA",
                    Timestamp = new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.FromHours(-7))
                },
                new StatusUpdate
                {
                    Description = "In transit",
                    Location = "Denver, CO",
                    Timestamp = new DateTimeOffset(2026, 5, 24, 6, 20, 0, TimeSpan.FromHours(-6))
                },
                new StatusUpdate
                {
                    Description = "Out for delivery",
                    Location = "Austin, TX",
                    Timestamp = new DateTimeOffset(2026, 5, 27, 8, 0, 0, TimeSpan.FromHours(-5))
                },
                new StatusUpdate
                {
                    Description = "Delivered",
                    Location = "Austin, TX",
                    Timestamp = new DateTimeOffset(2026, 5, 27, 11, 35, 0, TimeSpan.FromHours(-5))
                }
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Los Angeles, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Label created",
                    Location = "Los Angeles, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 28, 0, 10, 0, TimeSpan.FromHours(-7))
                }
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_76f92376efb64d11ae425cc7df8cad4d.Client.Models
@using sv_76f92376efb64d11ae425cc7df8cad4d.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
